import React, { useState, useEffect } from 'react';

export default function ExpertDashboard() {
  const [queries, setQueries] = useState([]);
  const [expertIdentity, setExpertIdentity] = useState('');
  const [typedAnswers, setTypedAnswers] = useState({});
  const [loading, setLoading] = useState(true);

  // University Corporate Theme colors
  const gbpuatGreen = "#004d40";

  // 1. Core Data Gathering function targeting our exact file script name
  const fetchPending = () => {
    setLoading(true);
    fetch('http://localhost/farmer-portal-backend/get_pending_queries.php')
      .then(res => {
        if (!res.ok) {
          throw new Error("Server returned error response code");
        }
        return res.json();
      })
      .then(data => {
        // Ensure data is array type before assigning to hooks
        if (Array.isArray(data)) {
          setQueries(data);
        } else {
          console.error("Unexpected data format structure:", data);
        }
        setLoading(false);
      })
      .catch(err => {
        console.error("Error connecting to query fetch endpoint:", err);
        setLoading(false);
      });
  };

  useEffect(() => {
    fetchPending();
  }, []);

  // 2. Submission handler routing solutions right back to MySQL
  const handleAnswerSubmit = async (queryId) => {
    if (!expertIdentity.trim()) {
      alert("Please state your Name & Department registration details first.");
      return;
    }
    if (!typedAnswers[queryId] || !typedAnswers[queryId].trim()) {
      alert("The solution text field cannot be sent empty.");
      return;
    }

    try {
      const response = await fetch('http://localhost/farmer-portal-backend/submit_solution.php', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          query_id: queryId,
          expert_name: expertIdentity,
          solution_text: typedAnswers[queryId]
        })
      });

      const result = await response.json();
      if (result.status === 'success') {
        alert("✅ Solution added cleanly. The items are now on the public bulletin board.");
        // Clear answered question field text out of state hooks
        setTypedAnswers(prev => {
          const updated = { ...prev };
          delete updated[queryId];
          return updated;
        });
        // Reload pending stream live
        fetchPending();
      } else {
        alert("Failed to save solution: " + result.message);
      }
    } catch (err) {
      alert("Communication crash connecting across to your backend folder api scripts.");
    }
  };

  if (loading) return <p style={{ padding: '20px', fontWeight: 'bold' }}>Loading pending farmer questions...</p>;

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif', textAlign: 'left' }}>
      <h2 style={{ color: gbpuatGreen, marginTop: 0 }}>🎓 University Extension Expert Command Desk</h2>
      <p style={{ color: '#555', marginBottom: '25px' }}>Provide verified treatment recommendations and clinical solutions to regional farming issues.</p>
      
      {/* Scientist Profile Input Identifier card */}
      <div style={{ padding: '15px', backgroundColor: '#f9f9f9', border: '1px solid #ddd', borderRadius: '6px', marginBottom: '25px' }}>
        <label style={{ display: 'block', fontWeight: 'bold', marginBottom: '5px', fontSize: '0.95rem' }}>Scientist/Professor Profile Identity Signature:</label>
        <input 
          type="text" 
          placeholder="e.g., Dr. S.N. Singh (Department of Plant Pathology)" 
          value={expertIdentity}
          onChange={(e) => setExpertIdentity(e.target.value)}
          style={{ width: '100%', padding: '10px', boxSizing: 'border-box', border: '1px solid #aaa', borderRadius: '4px' }}
        />
      </div>

      {queries.length === 0 ? (
        <div style={{ padding: '30px', textAlign: 'center', border: '2px dashed #ccc', borderRadius: '8px', backgroundColor: '#fafffa' }}>
          <p style={{ color: 'green', fontWeight: 'bold', fontSize: '1.2rem', margin: 0 }}>🎉 Great job! No incoming pending farmer queries require attention right now.</p>
          <p style={{ color: '#666', fontSize: '0.9rem', marginTop: '5px' }}>All questions submitted to the university database have been answered successfully.</p>
        </div>
      ) : (
        <div style={{ display: 'grid', gap: '20px' }}>
          {queries.map((q) => (
            <div key={q.id} style={{ padding: '20px', border: '1px solid #ccc', borderRadius: '6px', backgroundColor: '#fff', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.85rem', color: '#666', marginBottom: '10px', flexWrap: 'wrap', gap: '10px' }}>
                <span>🌾 Category: <b>{q.category}</b></span>
                <span>📍 Location: {q.location}</span>
                <span>Submitted by: <b>{q.farmer_name}</b></span>
              </div>
              <p style={{ fontStyle: 'italic', background: '#f5f5f5', padding: '12px', borderRadius: '4px', color: '#333', marginTop: 0, borderLeft: '4px solid #aaa' }}>
                "{q.question_text}"
              </p>
              
              <label style={{ display: 'block', fontWeight: 'bold', fontSize: '0.9rem', marginBottom: '5px' }}>Write Official University Advisory Solution:</label>
              <textarea
                rows="4"
                placeholder="Type precise treatment blueprints, chemicals names, application weights, or machinery diagnostic guidelines..."
                value={typedAnswers[q.id] || ''}
                onChange={(e) => setTypedAnswers({ ...typedAnswers, [q.id]: e.target.value })}
                style={{ width: '100%', padding: '10px', boxSizing: 'border-box', borderRadius: '4px', border: '1px solid #ccc', resize: 'vertical' }}
              />
              <button 
                onClick={() => handleAnswerSubmit(q.id)}
                style={{ marginTop: '12px', padding: '10px 20px', backgroundColor: gbpuatGreen, color: '#fff', border: 'none', cursor: 'pointer', borderRadius: '4px', fontWeight: 'bold' }}
              >
                Submit Verified Solution
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
